#include <math.h>
#include <stdio.h>
void simulate(const char *name,double eid,double mu,double mug,double dc,double mc){double output=100,ei=0.42,ap=1,temp=1.2;for(int y=2025;y<=2100;y+=5){if(y>2025){output*=pow(1.012,5);ei=fmax(0.02,ei*pow(1-eid,5));mu=fmin(0.98,mu+mug);}double e=output*ei*(1-mu);if(y>2025){ap=fmax(0,ap+0.012*e-0.010*ap);temp=fmax(0,temp+0.030*ap-0.012*temp);}double d=dc*temp*temp*output;double c=mc*mu*mu*output;double cons=fmax(0,output-d-c);double w=log(cons+1)/pow(1.015,y-2025);printf("%s,%d,%.6f,%.6f,%.6f,%.6f,%.6f,%.6f,%.6f,%.6f,%.6f,%.6f\n",name,y,output,ei,mu,e,ap,temp,d,c,cons,w);}}
int main(void){printf("scenario,year,output,emissions_intensity,mitigation_rate,emissions,atmospheric_pressure,temperature_proxy,damages,mitigation_cost,consumption_proxy,discounted_welfare_proxy\n");simulate("delayed_transition",0.006,0.02,0.010,0.012,0.040);simulate("moderate_transition",0.012,0.06,0.025,0.010,0.040);simulate("accelerated_decarbonization",0.018,0.10,0.045,0.008,0.055);simulate("high_innovation_pathway",0.026,0.08,0.040,0.008,0.038);return 0;}
